/**
 * @class BxProgress
 * @classDesc BxProgress 클래스 생성자
 *
 * @returns {object} 생성된 인스턴스
 *
 * @example
 *
 * <script>
 *
 *  $(document).ready(function(){
 *    // DOM이 ready된 시점에서 초기화 함수를 호출한다.
 *          $().BxProgress().initialize();
 *     });
 *
 *  window.formMethod = {
 *      sliderStart: function(value){
 *           this.stopDrag();
 *           alert('start')
 *       },
 *       sliderEnd: function(value){
 *           this.stopDrag();
 *           alert('end')
 *       },
 *       sliderChange: function(value){
 *           console.log('slider 값을 ' + value + '로 변경하였습니다.');
 *       },
 *       sliderRender: function(value){
 *           console.log('render');
 *       }
 *   };
 *
 *  </script>
 *
 * //---------------------------------------------------------------------------------------------------------
 * //---------------------------------------------------------------------------------------------------------
 * // bar type
 * //---------------------------------------------------------------------------------------------------------
 * //---------------------------------------------------------------------------------------------------------
 *
 *  <bx-progress id='progress1'
 *               type="bar"
 *               shape="round"
 *               label="theme"
 *               angle="horizon"
 *               effect="wave"
 *               decorator="{type:'tooltip', unit: '%'}"
 *               defaultValue="50"
 *               min="0"
 *               max="100"
 *               color="theme"
 *               colorLevel="4"
 *               size=default
 *               bx-start="formMethod.sliderStart"
 *               bx-end="formMethod.sliderEnd"
 *               bx-change="formMethod.sliderChange"
 *               bx-render ="formMethod.sliderRender">
 *  </bx-progress>
 *
 * //---------------------------------------------------------------------------------------------------------
 * //---------------------------------------------------------------------------------------------------------
 * // slider type
 * //---------------------------------------------------------------------------------------------------------
 * //---------------------------------------------------------------------------------------------------------
 *
 *  <bx-progress id='progress2'
 *               type="slider"
 *               label="값을 변경하면 이벤트가 발생합니다."
 *               decorator="{type:'tooltip', unit: '%'}"
 *               defaultValue="50"
 *               angle="horizon"
 *               min="0"
 *               max="100"
 *               step="10"
 *               icon="car"
 *               color="theme"
 *               colorLevel="5"
 *               size="large"
 *               bx-start="formMethod.sliderStart"
 *               bx-end="formMethod.sliderEnd"
 *               bx-change="formMethod.sliderChange"
 *               bx-render ="formMethod.sliderRender">
 *  </bx-progress>
 *
 * //---------------------------------------------------------------------------------------------------------
 * //---------------------------------------------------------------------------------------------------------
 * // circle type
 * //---------------------------------------------------------------------------------------------------------
 * //---------------------------------------------------------------------------------------------------------
 *
 *  <bx-progress id='progress3'
 *               type="circle"
 *               label="circle"
 *               shape="tooltip"
 *               decorator="{unit: '%'}"
 *               defaultValue="77"
 *               valueEffect="bounce"
 *               min="0"
 *               max="80"
 *               color="theme"
 *               colorLevel="4"
 *               size="large"
 *               bx-start="formMethod.sliderStart"
 *               bx-end="formMethod.sliderEnd"
 *               bx-change="formMethod.sliderChange">
 *</bx-progress>
 */

// 사용자에게 제공되는 API 목록
