const BXUI = require('../../../bx-ui-core/entry');
const $ = require('jquery');
const _ = require('lodash');

const BASE = require('../base');
const CONSOLE = BXUI.Console;
const UTIL = BXUI.Util;

/* color class setting */
const COLOR_CLASS_NAME = {
    theme: '',
    red: 'red',
    green: 'green',
    navy: 'navy',
    gray: 'gray'
};

/* size class setting */
const SIZE_CLASS_NAME = {
    default: 'default',
    tiny: 'tiny',
    large: 'large'
};

const SIZE_CONFIG = {
    labelSize: 20,
    defaultVerticalSize: 120
};

const COLOR_LEVEL_CLASS_NAME = ['color1', 'color2', '', 'color3', 'color4'];

/* effect class setting */
const EFFECT_CLASS_NAME = {
    pingpong: 'highlight',
    wave: 'highlight2',
    verticalpingpong: 'highlight3',
    verticalwave: 'highlight3'
};

/* animation config setting */
const ANIMATION_CONFIG = {
    duration: 2000
};

/* circle type size setting */
const CIRCLE_SIZE_CONFIG = {
    minWidth: 160,
    maxWidth: 1020,
    minFontSize: 20,
    maxFontSize: 140,
    strokeWidth: 8
};

class BxProgress {

    constructor(){
        this.$root = BxProgress.$root;
        this.opts = OPTS;
    }

    /**
     * 초기화 함수
     *
     * <p>
     *     DOM이 생성된 이후 (DOM Ready) 초기화 함수를 호출한다.
     * </p>
     *
     * @returns {object} 생성된 인스턴스
     */
    initialize(){

        this.$progress = this.$root.find('bx-progress');

        this.elems = [];

        $.each(this.$progress, (i, el) => {

            let $el = $(el),
                type = $el.attr('type') || 'bar',
                options = _createComponentOptions($el, OPTS.common);

            let $container = _parseCustomElement($el, options, type);
            let progressElem = $container.get(0);
            let bxRender = progressElem['bxrender'];

            _setValue.call($container, options.defaultValue);

            _setProgressColor($container, options.color);

            _setProgressColorLevel($container, options.colorLevel);

            if (options.type === 'slider') _setSliderMoveEvent.call($container);

            UTIL.addAllEventListenerWithProperty($container, options.events);

            bxRender.call(progressElem);

            this.elems.push($container.get(0));

        });

        return this;
    }
}

/**
 *
 * Custom Element 를 구별하기위한 플래그
 *
 * `커스텀 엘리먼트`의 경우에는 반드시 아래 프로퍼티값을 정의해야한다.
 *
 * @private
 * @type {boolean}
 */
BxProgress.isCustomElement = true;

/**
 * progress 값 설정 함수
 * @param {int} value - progress value
 * @alias setValue
 * @private
 * @memberOf BxProgress
 */
function _setValue(value){

    if (!_.isNumber(value)) {
        CONSOLE.prop.throw(BxProgress, 'value', 'type');
    }

    let $progressElem = $(this),
        progressElem = $progressElem.get(0),
        type = progressElem.type,
        angle = progressElem.angle,
        _k = UTIL.convertInternalPropertyName('defaultValue');

    if (value >= progressElem.max) value = progressElem.max;
    if (value <= progressElem.min) value = progressElem.min;

    progressElem[_k] = value;

    _setProgressValueText.call(this, value);

    if (type === 'circle'){
        _animateCircle.call(this, value);
    }
    else {

        let _value =  _getRateToValue.call(this, value);

        if (angle === 'vertical'){
            _setSliderHeight.call(this, _value);
        }
        else {
            _setSliderWidth.call(this, _value);
        }

    }

}

/**
 * progress의 현재 value 반환 함수
 *
 * @returns {int} progress value
 * @alias getValue
 * @private
 * @memberOf BxProgress
 */
function _getValue(){

    let $progressElem = $(this);

    return $progressElem.defaultValue;
}

/**
 * progress color 설정 함수
 * @param {string} theme|red|green|navy|gray - color name (theme|red|green|navy|gray)
 * @alias setColor
 * @private
 * @memberOf BxProgress
 */
function _setColor(colorName){

    if (!_.isString(colorName)) {
        CONSOLE.prop.throw(BxProgress, 'colorName', 'type');
    }

    if (!(colorName === 'theme' || colorName === 'red' || colorName === 'green' ||
        colorName === 'navy' || colorName === 'gray' || colorName === '')) {

        CONSOLE.prop.throw(BxProgress, 'colorName', 'value');
    }

    _resetProgressColor.call(this);

    _setProgressColor($(this), colorName);
}

/**
 * progress color level 설정 함수
 * @param {int} colorLevel - color level (1~5)
 * @alias setColorLevel
 * @private
 * @memberOf BxProgress
 */
function _setColorLevel(colorLevel){

    if (colorLevel && !_.isNumber(colorLevel)) {
        CONSOLE.prop.throw(BxProgress, 'colorLevel', 'type');
    }

    colorLevel = _getColorLevel(colorLevel);

    _resetProgressColorLevel.call(this);

    _setProgressColorLevel($(this), colorLevel);
}

/**
 * slider type의 drag event를 해제하는 함수
 * @alias stopDrag
 * @memberOf BxProgress
 */
function _stopDrag(){
    _stopDragMouseInBar.call(this);
}

/**
 * custom 태그를 native 태그로 치환한다.sliderStart
 * @param {object} $customElem - progress custom 컨테이너
 * @param {object} options - component options
 * @param {string} type - progress 타입
 *
 * @returns {object} 생성된 native element
 *
 * @private
 * @memberOf BxProgress
 */
function _parseCustomElement(
    $customElem = $(document.documentElement),
    options = {},
    type = 'default'
){

    let $container = BASE.appendContainerElement(BxProgress.$root, BxProgress.className);
    let $wrapper = $('<div></div>');

    _setNativeAttribute($container, options.attr);
    _setElementProperties(options, $container.get(0));

    // let html = _getComponentHtml($container, options, type);
    let html = _getComponentHtml($wrapper, options, type);

    $wrapper.append(html);
    $container.append($wrapper);

    $customElem.replaceWith($container);

    return $container;
}
/**
 * native attribute 설정 함수
 *
 * @param {object} $container - progress 컨테이너
 * @param {object} attr - native 속성
 *
 * @private
 * @memberOf BxProgress
 */
function _setNativeAttribute(
    $container = $(document.documentElement),
    attr = {}
){

    $.each(attr, (name, value)=>{
        if (name === 'class') return;
        $container.attr(name, value);
    });

    if (attr.class) $container.addClass(attr.class);
}
/**
 * circle type의 style 정보 반환 함수
 *
 * @returns {object} $container - progress container elemnt
 *
 * @private
 * @memberOf BxProgress
 */
function _getCircleStyleInfo($container = $(document.documentElement)){

    let width = $container.width();

    width = width < 160 ? 160 : width;

    let radius = width / 2;
    let strokeWidth = CIRCLE_SIZE_CONFIG.strokeWidth;
    let circleDiameter = (radius - strokeWidth) * 2 * 3.14;
    let minWidth = CIRCLE_SIZE_CONFIG.minWidth;
    let fontDrainage = Math.round((width / minWidth));
    let fontSize = CIRCLE_SIZE_CONFIG.minFontSize * fontDrainage;
    let fontMaxSize = CIRCLE_SIZE_CONFIG.maxFontSize;

    fontSize = fontSize > fontMaxSize ? fontMaxSize : fontSize;

    return {
        svg: {
            width: width,
            height: width
        },
        circle: {
            'r': radius - strokeWidth,
            'cy': radius,
            'cx': radius,
            'stroke-dasharray': circleDiameter
        },
        value: {
            'font-size': fontSize + 'px',
            'top': radius - fontSize/2 + 'px'
        },
        label: {
            'top': radius + fontSize/2 + 10 + 'px'
        }
    };
}

/**
 * progress color level 초기화 함수
 *
 * @private
 * @memberOf BxProgress
 */
function _resetProgressColorLevel(){

    let type = this.type;
    let $target;

    if (type === 'circle') $target =  $(this).find('.bx-progress');
    else $target =  $(this).find('.bx-progress-wrap');

    COLOR_LEVEL_CLASS_NAME.forEach((className, i)=>{
        $target.removeClass(className);
    });

}

/**
 * progress color 초기화 함수
 *
 * @private
 * @memberOf BxProgress
 */
function _resetProgressColor(){

    let $target = $(this).find('.bx-progress-wrap');

    $.each(COLOR_CLASS_NAME, (colorName, className)=>{
        $target.removeClass(className);
    });

}

/**
 * circle type의 원지름 반환 함수
 *
 * @param {object} $container - progress 컨테이너
 *
 * @returns {int} 계산된 원지름
 *
 * @private
 * @memberOf BxProgress
 */
function _getCircleDiameter($container = {}){

    let width = $container.find('svg').width();

    width = width < 160 ? 160 : width;

    let radius = width / 2;
    let strokeWidth = CIRCLE_SIZE_CONFIG.strokeWidth;

    return (radius - strokeWidth) * 2 * 3.14;
}

/**
 * circle type animate 함수
 *
 * @param {int} defaultValue - progress value
 *
 * @private
 * @memberOf BxProgress
 */
function _animateCircle(defaultValue){

    let $progressElem = $(this),
        $circle = $progressElem.find('circle'),
        value =  _getCircleValuePercent($progressElem, defaultValue);

    $circle.animate({'stroke-dashoffset': value}, {
        duration: ANIMATION_CONFIG.duration,
        queue: false // animate 비동기 처리
    });
}

/**
 * value 값으로 원지름의 값을 구하는 함수
 *
 * @param {object} $container - progress 컨테이너
 * @param {object} options - progress 옵션
 *
 * @returns {int} percent value
 *
 * @private
 * @memberOf BxProgress
 */
function _getCircleValuePercent(
    $container = $(document.documentElement),
    value = 0
){
    let strokeRadius = CIRCLE_SIZE_CONFIG.strokeWidth / 2,
        diameter = _getCircleDiameter($container),
        rate =  diameter / 100;

    return (100 - _getRateToValue.call($container, value)) * rate + strokeRadius;

}

/**
 * 타입별 progress html 반환 함수
 *
 * @param {object} $container - progress 컨테이너
 * @param {object} options - progress 옵션
 * @param {string} inputType - progress 타입
 *
 * @returns {object} 화면에 그려질 progress HTML
 *
 * @private
 * @memberOf BxProgress
 */
function _getComponentHtml(
    $container = $(document.documentElement),
    options = {},
    inputType = ''
){
    inputType !== 'circle' && _setCSSProgressWrap($container, options, inputType);

    switch (inputType){
        // case 'slider'   : return _getSliderTypeProgressHTML.call(this, options);
        case 'circle'   : return _getCircleTypeProgressHTML($container, options);
        case 'bar'      :
        case 'slider'   : return _getProgressHTML($container, options, inputType);
    }
}

/**
 * BXprogress wrap의 css 설정 함수
 *
 * @param {object} $container - progress 컨테이너
 * @param {object} options - progressbar 옵션
 * @param {string} inputType - progressbar 타입
 *
 * @private
 * @memberOf BxProgress
 */
function _setCSSProgressWrap(
    $container = $(document.documentElement),
    options = {},
    inputType = 'default'
){

    let label = options.label,
        size = options.size,
        angle = options.angle,
        icon = options.icon,
        type = options.decorator.type;

    if (!_.isString(inputType) || inputType.length === 0 || inputType === 'circle') return;

    // progressbar size
    if (size !== 'default') $container.addClass(`size-${size}`);

    // progressbar 수직 or 수평 설정
    if ( angle === 'vertical') {
        $container.addClass('type-vertical');
    }
    else {
        $container.addClass('type-inline');
    }

    if (inputType === 'bar'){

        // 툴팁 위치
        if (type === 'tooltip'){

            if (angle === 'vertical'){
                $container.addClass('add-num');
            }
            else {
                $container.addClass('add-top');
            }
        }
    } else {

        // 툴팁 위치
        if (angle === 'vertical'){
            // 세로 인 경우엔 무조건 기본형 ( 아이콘이 없음 )
            $container.addClass('add-btn');
        }
        else {

            if (type === 'tooltip'){
                // 툴팁이 있는 경우
                if (!_.isUndefined(icon)){
                    // 툴팁과 아이콘이 다 있는 경우
                    $container.addClass('add-all');
                }
                else {
                    // 아이콘이 없는 경우
                    $container.addClass('add-btn-all');
                }
            }
            else {
                // 툴팁이 없는 경우
                if (!_.isUndefined(icon) && (icon === 'car' || icon === 'horse')){
                    // 아이콘이 progress 위에 있는 경우 (car, horse)
                    $container.addClass('add-top');
                }
                else if (!_.isUndefined(icon)){
                    // 아이콘이 progress 아래 있는 경우 (cablecar)
                    $container.addClass('add-btm');
                }
                else {
                    // 툴팁과 아이콘이 다 없는 경우
                    $container.addClass('add-btn');
                }
            }
        }
    }
}


/**
 * circle type progress html 반환 함수
 *
 * @param {object} $container -  progress 컨테이너
 * @param {object} options - component options
 *
 * @returns {string} 화면에 그려질 progress html
 *
 * @private
 * @memberOf BxProgress
 */
function _getCircleTypeProgressHTML(
    $container = $(document.documentElement),
    options = {}
){

    let label = options.label;
    let decorator = options.decorator;
    let styleInfo = _getCircleStyleInfo($container);

    let svgStyle = styleInfo.svg;
    let valueStyle = styleInfo.value;
    let labelStyle = styleInfo.label;
    let circleStyle = styleInfo.circle;

    let svgAttr = `style="width:${svgStyle.width}px;height:${svgStyle.width}px;"`;

    let circleAttr = [];

    circleAttr.push(`class="circle_animation"`);
    circleAttr.push(`r="${circleStyle.r}"`);
    circleAttr.push(`cx="${circleStyle.cx}"`);
    circleAttr.push(`cy="${circleStyle.cy}"`);
    circleAttr.push(`style="stroke-dasharray: ${circleStyle['stroke-dasharray']};`);
    circleAttr.push(`stroke-dashoffset:${circleStyle['stroke-dasharray']}"`);
    circleAttr.push('fill="none"');

    let html = [];

    html.push('<div class="'+ _getCircleTypeWrapClass(options) +'">');

    if (label){

        let labelAttr = 'class="bx-label"' +
            'style="top:' + labelStyle.top + ';"';
        html.push('<p '+labelAttr+'>'+ label +'</p>');
    }

    if (decorator){

        let valutStyleText = 'top:' + valueStyle.top + ';' +
            'font-size:' + valueStyle['font-size'];

        html.push(_getValueSignHTML(options, valutStyleText));
    }

    html.push('<svg '+ svgAttr +'>');
    html.push('<g>');
    html.push('<circle ' + circleAttr.join(' ') + '></circle>');
    html.push('</g>');
    html.push('</svg>');

    return html.join('');
}

/**
 * progress html 반환 함수
 *
 * @param {object} options - progress 옵션
 * @param {object} inputType - progress 타입
 *
 * @returns {string} 화면에 그려질 progress html
 *
 * @private
 * @memberOf BxProgress
 */
function _getProgressHTML(
    $container = $(document.documentElement),
    options = {},
    inputType = 'default'
){

    let label = options.label,
        icon = options.icon,
        type = options.decorator.type,
        effect = options.effect,
        angle = options.angle,
        shape = options.shape,
        rate = _getRateToValue.call($container);

    let html = [];
    let progressLength = angle === 'vertical' ? `height:${rate}%` : `width:${rate}%`;
    effect = angle === 'vertical' ? 'vertical'+effect : effect;

    // square는 명칭을 css에 맞게 변경
    // vertical dotted 타입은 전부 기본형으로 변경
    if (shape === 'square'){
        shape = 'squared';
    }
    else if (shape === 'dotted' && angle === 'vertical'){
        shape = 'round';
    }

    html.push(`<div class="bx-progress-wrap ${shape}">`);

    if (label && angle !== 'vertical') html.push(`<p class="bx-label">${label}</p>`);

    html.push(`<div class="bx-progress" ${!label ? 'style="left:0;"' : ''}>`);
    html.push(`<div class="${_getBarClass(effect)}" style="${progressLength}">`);

    inputType === 'slider' && html.push(_getIconClassHTML(angle, icon));
    type === 'tooltip' && html.push(_getValueSignHTML(options));

    html.push('</div>');
    html.push('</div>');
    html.push('</div>');

    if (label && angle === 'vertical') html.push(`<p class="bx-label">${label}</p>`);

    let height = $container.height();

    if (angle === 'vertical') {

        if (height === 0){
            // 높이를 지정 하지 않을 경우 최소 120px로 설정
            $container.css('height', SIZE_CONFIG.defaultVerticalSize);
        }
        else {
            // label 값이 있는 경우
            if (label) $container.css('height', (height - SIZE_CONFIG.labelSize));
        }

    }

    return html.join('');
}

/**
 * slider Type별 icon html 반환 함수
 *
 * @param {string} angle - progress angle
 * @param {string} icon - progress 아이콘
 *
 * @returns {string} icon html
 *
 * @private
 * @memberOf BxProgress
 */
function _getIconClassHTML(
    angle = '',
    icon = ''
){
    let html = '',
        iconClass = 'default';

    if (angle !== 'vertical'){

        switch (icon){
            case 'car'      : iconClass = 'icon-type i-car moving'; break;
            case 'cablecar' : iconClass = 'icon-type i-cablecar swing'; break;
            case 'horse'    : iconClass = 'icon-type i-horse swing'; break;
        }
    }

    html = `<span class="bx-ctrl-btn ${iconClass}"></span>`;

    return html;
}

/**
 * value decorator html 반환 함수
 *
 * @param {object} component options
 * @param {string} style - progress circle타입 style
 *
 * @returns {string} decorator html
 *
 * @private
 * @memberOf BxProgress
 */
function _getValueSignHTML(
    options = {},
    style = ''
){
    let html = [],
        elClass = 'bx-num',
        type = options.type,
        decorator = options.decorator,
        num = options.defaultValue,
        effect = options.valueEffect,
        unit = decorator.unit;

    if (type === 'circle' && effect === 'bounce') elClass += ' rubberband';

    html.push(`<span class="${elClass}" style="${style}">`);
    html.push('<b></b>');

    if (unit) html.push(`<span class="unit">${unit}</span>`);

    html.push('</span>');

    return html.join('');
}

/**
 * bar type progress class 반환 함수
 *
 * @param {string} effect - progress animation 타입
 *
 * @returns {string} 생성된 animation class
 *
 * @private
 * @memberOf BxProgress
 */
function _getBarClass(effect = ''){
    let barClass = 'bx-bar';
    if (effect) barClass += ' ' + EFFECT_CLASS_NAME[effect];
    return barClass;
}

