/**
 * circle type progress class 반환 함수
 *
 * @param {object} component options
 *
 * @returns {string} circle wrap html
 *
 * @private
 * @memberOf BxProgress
 */
function _getCircleTypeWrapClass(options = {}){

    let size = options.size,
        color = options.color,
        effect = options.effect;

    let elClass = `bx-progress circle size-${size}`;

    if (color && color !== 'theme') elClass += ' ' + COLOR_CLASS_NAME[color];

    if (effect && effect !== 'pingpong') elClass += ' ' + EFFECT_CLASS_NAME[effect];

    return elClass;
}

/**
 * value의 백분율 반환 함수
 *
 * @param {int} value - progress value
 *
 * @returns {int} 기본값을 백분율로 변환한
 *
 * @private
 * @memberOf BxProgress
 */
function _getRateToValue(value){

    let $progressElem = $(this);
    let progressElem = $progressElem.get(0);

    let min = parseInt(progressElem.min),
        max = parseInt(progressElem.max),
        num = parseInt(value);

    if (num > max) num = max;
    if (num < min) num = min;

    return parseFloat((num - min) / (max - min) * 100);
}

/**
 * colorLevel 값을 반환한다.
 *
 * @param {int} colorLevel - colorLevel 값
 *
 * @private
 *
 * @memberOf BxProgress
 */
function _getColorLevel(colorLevel){

    if (colorLevel < 1) colorLevel = 1;

    if (colorLevel > 5) colorLevel = 5;

    return colorLevel;
}

/**
 * component options 반환 함수
 *
 * @param {object} $container - Progress 컨테이너
 *
 * @returns {object} 설정된 Progress 옵션
 *
 * @private
 * @memberOf BxProgress
 */
function _createComponentOptions($targetObject = null, opt = {}){

    if (!_.isFunction($targetObject.get) && !_.isPlainObject($targetObject)){
        CONSOLE.prop.throw(BxProgress, 'targetObject', 'type');
    }

    let defaultOpts = $.extend({}, opt),
        type = $targetObject.attr('type');

    switch(type){

        case 'bar': $.extend(defaultOpts, OPTS.bar); break;

        case 'slider': $.extend(defaultOpts, OPTS.slider); break;

        case 'circle': $.extend(defaultOpts, OPTS.circle); break;

        default : $.extend(defaultOpts, OPTS.bar);

    }

    let opts = UTIL.createComponentOptions($targetObject, defaultOpts, ATTRNAMES, function(k, v){

        if (k === 'decorator') {

            return _parseObject(k, v);
        }

        return v;

    }, function(k, v){

        let _opts = this;

        //if (!_.isPlainObject(_opts.events)) _opts.events = {};

        if (k === 'class'){
            v = ' ' + v;
        }

        // 이벤트 핸들러
        //if (k.match(/^bx-/)) {
        //
        //    _opts.events[k] = v;
        //    return;
        //}

        return v;

    });

    _checkValueType(opts);// 유효성 검사

    return  $.extend(opts, _setCommonDefaultValue(opts));
}


/**
 * 프로퍼티 세팅 함수
 *
 * @param {object} 옵션 객체
 * @param {object} 프로퍼티를 세팅할 엘리먼트
 *
 * @private
 * @memberOf BxProgress
 */
function _setElementProperties(opts = {}, elem = null){

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw(BxProgress, 'opts', 'type');
    }

    if (!_.isElement(elem)){
        CONSOLE.prop.throw(BxProgress, 'elem', 'type');
    }

    _.map(opts, (v, k) => {

        // attr 속성은 무시한다.
        if (k === 'attr') return;
        // events 속성은 무시한다.
        if (k === 'events') return;

        if (k.match(/^bx-/)){

            let _k = k.replace('-', '');
            delete opts[k];
            k = _k;
        }

        // 읽기 전용 속성
        if (
            k === 'fill' || k === 'decorator' ||
            k === 'angle'|| k === 'min'||
            k === 'max' || k === 'icon'||
            k === 'label' || k === 'size'||
            k === 'effect' || k === 'type' ||
            k === 'shape' || k === 'step'
        ){

            if (k ==='step' || k === 'min' || k === 'max') {
                v = parseInt(v);
            }

            UTIL.setReadOnlyProperty(elem, k, v);
        }
        else {

            let _k = UTIL.convertInternalPropertyName(k);

            elem[_k] = v;

            UTIL.setPropertyWithDescriptor(elem, k, {
                configurable: true,
                enumerable: true,
                get: () => {
                    return elem[_k];
                },
                set: (v) => {
                    switch (k){
                        case 'color' :
                            elem[_k] = v;
                            _setColor.call(elem, v); break;

                        case 'colorLevel' :
                            elem[_k] = v;
                            _setColorLevel.call(elem, v); break;

                        case 'defaultValue' :
                            elem[_k] = v;
                            _changeValue.call(elem, v);
                            break;

                        case 'bxrender':
                        case 'bxchange':
                        case 'bxstart':
                        case 'bxend':
                            if (!_.isFunction(v) ){
                                CONSOLE.prop.throw(BxProgress, k, 'type');
                            }
                            elem[_k] = v;
                            break;
                    }
                }
            });
        }
    });

    _.map(APIS, (v, k) => {

        UTIL.setReadOnlyProperty(elem, k, v);
    });

    return this;
}

/**
 * 공통 options의 초기값 설정 함수
 *
 * @param {} options
 * @param {string} [options.label] - 라벨
 * @param {string} [options.min] - progress 최소 값
 * @param {string} [options.max] - progress 최대 값
 * @param {string} [options.size] - progress 크기
 * @param {string} [options.color] - progress 색상
 * @param {string} [options.colorLevel] - progress 색상농도
 * @param {string} [options.decorator] - value 옵션
 * @param {string} [options.defaultValue] - 초기값
 *
 * @returns {object} 초기값이 설정된 options
 *
 * @private
 * @memberOf BxProgress
 */
function _setCommonDefaultValue({
    label = '',
    min = 0,
    max = 100,
    size = 'default',
    color = 'theme',
    colorLevel = 3,
    decorator = {
        type : 'default',
        unit : ''
    },
    defaultValue = 0,
    shape = 'round'
}){

    if (_.isUndefined(decorator.type)) decorator.type = 'default';

    if (_.isUndefined(decorator.unit)) decorator.unit = '';

    if (defaultValue) defaultValue = parseInt(defaultValue);

    if (min) min = parseInt(min);

    if (max) max = parseInt(max);

    if (max <= min) max = min;

    if (_.isString(color) && _.isUndefined(COLOR_CLASS_NAME[color])) color = 'theme';

    if (!_.isUndefined(colorLevel) && isNaN(colorLevel)) colorLevel = 3;

    return {
        label: label,
        min: min,
        max: max,
        size: size,
        shape: shape,
        color: color,
        colorLevel: colorLevel,
        decorator: decorator,
        defaultValue: defaultValue
    };
}

/**
 * component option 유효성 검사 함수
 *
 * @param {object} options - progress 옵션
 *
 * @private
 * @memberOf BxProgress
 */
function _checkValueType(options = {}){

    let decorator = options.decorator,
        min = options.min,
        max = options.max,
        step = options.step,
        size = options.size,
        label = options.label,
        defaultValue = options.defaultValue;

    if (decorator && !_.isPlainObject(decorator)) {
        CONSOLE.prop.throw(BxProgress, 'decorator', 'type');
    }

    if (defaultValue && !_.isNumber(parseInt(defaultValue))){
        CONSOLE.prop.throw(BxProgress, 'defaultValue', 'type');
    }

    if (min && !_.isNumber(parseInt(min))) {
        CONSOLE.prop.throw(BxProgress, 'min', 'type');
    }

    if (max && !_.isNumber(parseInt(max))) {
        CONSOLE.prop.throw(BxProgress, 'max', 'type');
    }

    if (step && !_.isNumber(parseInt(step))) {
        CONSOLE.prop.throw(BxProgress, 'step', 'type');
    }

    if (size && (!_.isString(size) || _.isUndefined(SIZE_CLASS_NAME[size]))){
        CONSOLE.prop.throw(BxProgress, 'size', 'all');
    }

    if (label && (!_.isString(label) || label.length === 0)){
        CONSOLE.prop.throw(BxProgress, 'label', 'all');
    }

}

/**
 * 색상 레벨 설정 함수
 *
 * @param {object} $container - progress 컨테이너
 * @param {object} options - progress 옵션
 *
 * @private
 * @memberOf BxProgress
 */
function _setProgressColorLevel(
    $container = $(document.documentElement),
    colorLevel = 3
){

    let _colorLevel = _getColorLevel(colorLevel);
    let type = $container.get(0).type;
    let $progress;

    if (type === 'circle') $progress =  $container.find('.bx-progress');
    else $progress =  $container.find('.bx-progress-wrap');

    $progress.addClass(COLOR_LEVEL_CLASS_NAME[_colorLevel - 1]);
}

/**
 * 색상 설정 함수
 *
 * @param {object} $container - progress 컨테이너
 * @param {object} options - progress 옵션
 *
 * @private
 * @memberOf BxProgress
 */
function _setProgressColor(
    $container = $(document.documentElement),
    color = 'theme'
){

    let type = $container.get(0).type;

    if (type === 'circle') $container.find('.bx-progress').addClass(COLOR_CLASS_NAME[color]);
    else $container.find('.bx-progress-wrap').addClass(COLOR_CLASS_NAME[color]);

}

/**
 * slider type drag event bind 함수
 *
 * @private
 * @memberOf BxProgress
 */
function _setSliderMoveEvent(){

    this.find('.bx-progress')
        .on('mousedown', _startDragMouseInBar.bind(this));

    $(window).on('mouseup.BXprogressEnd', _stopDragMouseInBar.bind(this));
}

/**
 * slider type drag start event bind 함수
 *
 * @param {object} event 객체
 *
 * @private
 * @memberOf BxProgress
 */
function _startDragMouseInBar(e){

    let $progressElem = $(this);
    let progressElem = $progressElem.get(0);
    let value = _getSliderValueAndLength.call(this, e);

    if (progressElem.angle !== 'vertical'){
        _changeValue.call(this, Math.round(value.width));
    }
    else {
        _changeValue.call(this, Math.round(value.height));
    }

    $(window).on('mousemove.BXprogressDrag', _dragMouseInBar.bind(this));
}

/**
 * slider type drag event off 함수
 *
 * @private
 * @memberOf BxProgress
 */
function _stopDragMouseInBar(){

    let $progressElem = $(this);

    $progressElem.css('cursor', 'pointer');

    $(window).off('mousemove.BXprogressDrag');
}

/**
 * slider type drag event
 *
 * @param {object} event 객체
 *
 * @private
 * @memberOf BxProgress
 */
function _dragMouseInBar(e){

    let $progressElem = $(this);
    let progressElem = $progressElem.get(0);
    let value = _getSliderValueAndLength.call(this, e);

    if (progressElem.defaultValue !== value){

        if (progressElem.angle !== 'vertical'){
            _changeValue.call(this, Math.round(value.width));
        }
        else {
            _changeValue.call(this, Math.round(value.height));
        }
    }
}

/**
 * slider change handler
 *
 * @param {int} value - 변경될 값
 *
 * @private
 * @memberOf BxProgress
 */
function _changeValue(value){
    _setValue.call(this, value);
    _callDirectiveBXEvent.call(this);
}

/**
 * value 세팅 함수
 *
 * @param {int} value - 설정 할 값
 *
 * @private
 * @memberOf BxProgress
 */
function _setProgressValueText(value){

    if (value >= this.max) value = this.max;
    if (value <= this.min) value = this.min;

    $(this).find('.bx-num b').text(value);
}

/**
 * slider bar width 설정 함수
 * @param {int} value - 설정 할 값
 * @private
 * @memberOf BxProgress
 */
function _setSliderWidth(width){

    $(this).find('.bx-bar').css('width', width + '%');
}

/**
 * slider bar height 설정 함수
 * @param {int} value - 설정 할 값
 * @private
 * @memberOf BxProgress
 */
function _setSliderHeight(height){

    $(this).find('.bx-bar').css('height', height + '%');
}

/**
 * slider value, width 반환 함수
 * @param {object} e - drag event obejct
 * @private
 * @memberOf BxProgress
 */
function _getSliderValueAndLength(e){

    let $progressElem = $(this);
    let progressElem = $progressElem.get(0);

    let max = parseInt(progressElem.max),
        min = parseInt(progressElem.min),
        value = parseInt(progressElem.defaultValue);

    let step = parseInt(progressElem.step) || 1;

    let $target = this.find('.bx-progress');
    let prevWidth = $target.find('.bx-bar').width();
    let prevHeight = $target.find('.bx-bar').height();

    if (step < min) step = min;
    if (step > max) step = max;

    let totalWidth = $target.width();
    let totalHeight = $target.height();
    let widthPointer = e.clientX - $target.offset().left;
    let heightPointer = ($target.offset().top + totalHeight) - e.pageY;

    let widthPerStep = totalWidth * (step / max);
    let heightPerStep = totalHeight * (step / max);

    let widthPosition = widthPointer - prevWidth;
    let heightPosition = heightPointer - prevHeight;

    let widthCell = widthPosition % step;
    let heightCell = heightPosition % step;
    let modifiedWidthPosition = (widthCell > (step /2))? widthPosition + step - widthCell : widthPosition - widthCell;
    let modifiedHeightPosition = (heightCell > (step /2))? heightPosition + step - heightCell : heightPosition - heightCell;

    let offsetWidthStep = Math.round(modifiedWidthPosition / widthPerStep);
    let offsetHeightStep = Math.round(modifiedHeightPosition / heightPerStep);
    let offsetWidth = offsetWidthStep * widthPerStep;
    let offsetHeight = offsetHeightStep * heightPerStep;

    let _widthPosition = value + (offsetWidthStep * step);
    let _heightPosition = value + (offsetHeightStep * step);
    let widthRate = (prevWidth + offsetWidth) / totalWidth * 100;
    let heightRate = (prevHeight + offsetHeight) / totalHeight * 100;

    if (widthRate > 100) widthRate = 100;
    if (heightRate > 100) heightRate = 100;

    return {
        widthPosition: _widthPosition,
        width: widthRate,
        heightPosition: _heightPosition,
        height: heightRate
    };
}


/**
 * directive event bind 함수
 * @private
 * @memberOf BxProgress
 */
function _callDirectiveBXEvent(){

    let $progressElem = $(this);
    let progressElem = $progressElem.get(0);

    let bxChange = progressElem['bxchange'];
    let bxStart = progressElem['bxstart'];
    let bxEnd = progressElem['bxend'];
    let value = progressElem.defaultValue;

    if (bxChange) bxChange.call(progressElem, value);
    if (bxStart && value === parseInt(progressElem.min)) bxStart.call(progressElem, value);
    if (bxEnd && value === parseInt(progressElem.max)) bxEnd.call(progressElem, value);
}

/**
 * object parsing 함수
 * @param {string} name - 함수 명
 * @param {string} string - JSON Object로 변환 할 텍스트
 * @returns {object} 변환된 JSON Object
 * @private
 * @memberOf BxProgress
 */
function _parseObject(name = '', string = ''){

    try {
        return UTIL.JSParser(string);
    }
    catch (e){
        CONSOLE.prop.throw(BxProgress, name, 'type');
    }
}

module.exports = BxProgress;